import React, { useCallback, useMemo, useState } from 'react';
import {
  Button,
  Input,
  Modal,
  SearchTextInput,
  dispatchAppToast,
  LeaveConfirmModal,
  LinListFilterField,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { TransferTemplateDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useCatalogMasterListRowMenu } from '../../../hooks/useCatalogMasterListRowMenu';
import {
  CatalogCompanyField,
  useCatalogListPaging,
  useServerPagedListLoading,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogListMasterLinPageLayout,
  CatalogFormHistorySlot,
  CatalogFormCodeReplaceSlot,
  CatalogListHeaderFilters,
  CatalogRowActionMenu,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
  proposalEditableFields,
  toProposalFieldDefs,
} from '../../../components/catalog/catalogUiSchema';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-ket-chuyen';
const CATALOG_KIND = 'transfer-templates';

type FormErrors = Partial<Record<'code' | 'name' | 'debitAccountCode' | 'creditAccountCode', string>>;

const KetChuyenPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<TransferTemplateDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<TransferTemplateDto | null>(null);
  const [form, setForm] = useState<Partial<TransferTemplateDto>>({});
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);

  const { schema, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const proposalFieldDefs = useMemo(
    () => toProposalFieldDefs(proposalEditableFields(schema)),
    [schema],
  );

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const {
    showTableLoading,
    pageLoading,
    pulseSearch,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();

  const totalCount = items.length;
  const pagedItems = useMemo(() => {
    const start = (page - 1) * pageSize;
    return items.slice(start, start + pageSize);
  }, [items, page, pageSize]);

  const selection = useCatalogListSelection({
    rows: pagedItems,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = () => {
    setLoadingMode('filter');
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  const handleSearch = () => {
    pulseSearch(() => {
      setLoadingMode('filter');
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };

  React.useEffect(() => {
    let cancelled = false;
    beginFetch();
    const t = setTimeout(() => {
      masterService.getTransferTemplates({ search: search || undefined })
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => {
          if (!cancelled) dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải mẫu kết chuyển', type: 'error' });
        })
        .finally(() => { if (!cancelled) endFetch(); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã mẫu kết chuyển';
    if (!form.name?.trim()) next.name = 'Nhập tên mẫu kết chuyển';
    if (!form.debitAccountCode?.trim()) next.debitAccountCode = 'Nhập TK Nợ';
    if (!form.creditAccountCode?.trim()) next.creditAccountCode = 'Nhập TK Có';
    return next;
  };

  const closeFormModal = () => {
    setModalOpen(false);
    markClean();
  };

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({});
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openView = useCallback((row: TransferTemplateDto) => {
    setViewOnlyShared(true);
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const openEditImpl = useCallback((row: TransferTemplateDto) => {
    setViewOnlyShared(false);
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const rowMenu = useCatalogMasterListRowMenu({
    testIdPrefix: TEST_ID,
    catalogKind: CATALOG_KIND,
    selection,
    openEdit: openEditImpl,
    openView,
  });

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updateTransferTemplate(editing.id, form);
      else await masterService.createTransferTemplate(form);
      dispatchAppToast(dispatch, { message: editing ? 'Cập nhật mẫu kết chuyển thành công' : 'Tạo mẫu kết chuyển thành công', type: 'success' });
      markClean();
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.id)
        : [...selection.selectedIds].filter(id => {
            const row = pagedItems.find(r => r.id === id) ?? items.find(r => r.id === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updateTransferTemplate(id, { ...row, isActive: false });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} mẫu kết chuyển`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteTransferTemplate(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} mẫu kết chuyển`, type: 'success' });
    }
    refresh();
  };

  const filterBar = (
    <CatalogListHeaderFilters testIdPrefix={TEST_ID} filterMaxWidthPx={1000}>
      <LinListFilterField testId={`${TEST_ID}-field-search`}>
        <SearchTextInput
          label="Tìm kiếm"
          placeholder="Tìm mã, tên..."
          value={searchDraft}
          onChange={setSearchDraft}
          onSearch={handleSearch}
          testId={`${TEST_ID}-search-text`}
        />
      </LinListFilterField>
    </CatalogListHeaderFilters>
  );

  return (
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={pagedItems.filter(r => !isSharedCatalogReadOnly(r))}
        onAdd={openAdd}
        onEdit={rowMenu.openEditWithPerm}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        proposalFieldDefs={proposalFieldDefs.length > 0 ? proposalFieldDefs : undefined}
        toolbarBridgeRef={rowMenu.toolbarBridgeRef}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setLoadingMode('page'); setPage(p); selection.clearSelection(); }}
        onPageSizeChange={size => { setLoadingMode('filter'); setPageSize(size); }}
        showTableLoading={showTableLoading}
        pageLoading={pageLoading}
        header={{ title: 'Mẫu kết chuyển', titleIconClass: 'fas fa-random' }}
        listTitle="Danh sách mẫu kết chuyển"
        listRowMenuHelp
        filtersTestId={`${TEST_ID}-filters`}
        filterMaxWidthPx={1000}
        filters={filterBar}
        schemaEditorModal={(
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => {
              reloadSchema();
              refresh();
            }}
          />
        )}
        extraModals={(
          <>
            <CatalogRowActionMenu {...rowMenu.rowActionMenuProps} />
            <LeaveConfirmModal {...leaveConfirmModalProps} />
          </>
        )}
      >
        {pagedItems.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy mẫu phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : listColumns.length > 0 ? (
          <CatalogListGridFromSchema
            testIdPrefix={TEST_ID}
            rows={pagedItems}
            page={page}
            pageSize={pageSize}
            columns={listColumns}
            schema={schema}
            selection={selection}
            getRowId={r => r.id}
            isRowSelectable={r => !isSharedCatalogReadOnly(r)}
            {...rowMenu.gridRowMenuProps}
          />
        ) : null}
      </CatalogListMasterLinPageLayout>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem mẫu kết chuyển dùng chung' : editing ? 'Sửa mẫu kết chuyển' : 'Thêm mẫu kết chuyển'}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-debitAccountCode`}>
                <label className={styles.label}>TK Nợ *</label>
                <Input
                  value={form.debitAccountCode ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.debitAccountCode}
                  placeholder="911..."
                  onChange={e => {
                    markDirty();
                    clearFieldError('debitAccountCode');
                    setForm(f => ({ ...f, debitAccountCode: e.target.value }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-creditAccountCode`}>
                <label className={styles.label}>TK Có *</label>
                <Input
                  value={form.creditAccountCode ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.creditAccountCode}
                  placeholder="421..."
                  onChange={e => {
                    markDirty();
                    clearFieldError('creditAccountCode');
                    setForm(f => ({ ...f, creditAccountCode: e.target.value }));
                  }}
                />
              </div>
            </div>
          </div>
          <CatalogCompanyField
            testIdPrefix={TEST_ID}
            companyName={editing?.companyName ?? sessionCompanyName}
          />
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{
              name: form.name,
              debitAccountCode: form.debitAccountCode,
              creditAccountCode: form.creditAccountCode,
            }}
            {...sharedForm}
          />
          <div className={styles.modalActions}>
            <CatalogFormHistorySlot
              testIdPrefix={TEST_ID}
              catalogKind={CATALOG_KIND}
              editing={editing ? { id: editing.id, code: editing.code } : null}
            />
            <Button variant="secondary" onClick={closeFormModal}>Hủy</Button>
            <Button
              variant="primary"
              onClick={handleSave}
              disabled={saving || viewOnlyShared}
              data-testid={`${TEST_ID}-save-btn`}
            >
              {saving ? 'Đang lưu...' : 'Lưu'}
            </Button>
          </div>
        </div>
      </Modal>
    </>
  );
};

export default KetChuyenPage;
